   118→/// Abstract base trait for crate collision behaviors
   119→pub trait CrateCollideBehavior: Send + Sync {
   120→    /// Execute the crate's specific behavior when collected
   121→    fn execute_crate_behavior(&mut self, other: &dyn GameObject) -> Result<bool, CollisionError>;
   122→    
   123→    /// Check if this crate is valid to be executed by the given object
   124→    fn is_valid_to_execute(&self, other: &dyn GameObject) -> bool;
   125→}
