   127→/// Base crate collision module implementation
   128→pub struct CrateCollide {
   129→    /// Base collision module
   130→    base_module: CollideModule,
   131→    /// Crate-specific configuration
   132→    module_data: CrateCollideModuleData,
   133→    /// Thread-safe state
   134→    state: Arc<Mutex<CrateCollideState>>,
   135→}
   136→
   137→impl CrateCollide {
   138→    pub fn new(object_id: ObjectID, module_data: CrateCollideModuleData) -> Self {
   139→        Self {
   140→            base_module: CollideModule::new(object_id, module_data.base.clone()),
   141→            module_data,
   142→            state: Arc::new(Mutex::new(CrateCollideState {
   143→                is_collected: false,
   144→                creation_time: 0, // Would be set to current game time
   145→            })),
   146→        }
   147→    }
   148→    
   149→    pub fn get_module_data(&self) -> &CrateCollideModuleData {
   150→        &self.module_data
   151→    }
   152→    
   153→    pub fn is_collected(&self) -> Result<bool, CollisionError> {
   154→        let state = self.state.lock().map_err(|e| 
   155→            CollisionError::InvalidObject(format!("Failed to acquire state lock: {}", e))
   156→        )?;
   157→        Ok(state.is_collected)
   158→    }
   159→    
   160→    pub fn set_collected(&self, collected: bool) -> Result<(), CollisionError> {
   161→        let mut state = self.state.lock().map_err(|e| 
   162→            CollisionError::InvalidObject(format!("Failed to acquire state lock: {}", e))
   163→        )?;
   164→        state.is_collected = collected;
   165→        Ok(())
   166→    }
