   168→    /// Check if the given object is valid to execute this crate
   169→    pub fn is_valid_to_execute(&self, other: &dyn GameObject) -> bool {
   170→        // Ground never picks up a crate (handled by None check in caller)
   171→        
   172→        // Nothing Neutral can pick up any type of crate
   173→        if self.is_neutral_controlled(other) {
   174→            return false;
   175→        }
   176→        
   177→        let is_building = self.is_kind_of(other, KINDOF_STRUCTURE);
   178→        let valid_building_attempt = self.module_data.is_building_pickup && is_building;
   179→        
   180→        // Must be a "Unit" type thing with AI, or a valid building
   181→        if !self.has_ai_update_interface(other) && !valid_building_attempt {
   182→            return false;
   183→        }
   184→        
   185→        // Must match our kindof flags (if any)
   186→        if !self.is_kind_of_multi(other, self.module_data.required_kind_of, self.module_data.forbidden_kind_of) {
   187→            return false;
   188→        }
   189→        
   190→        if other.is_effectively_dead() {
   191→            return false;
   192→        }
   193→        
   194→        // Crates cannot be claimed while in the air, except by buildings
   195→        if self.is_above_terrain(other) && !valid_building_attempt {
   196→            return false;
   197→        }
   198→        
   199→        // Check owner player restriction
   200→        if self.module_data.is_forbid_owner_player {
   201→            if let Some(crate_owner) = self.get_controlling_player_for_object(self.base_module.get_object_id()) {
   202→                if crate_owner == other.get_controlling_player() {
   203→                    return false;
   204→                }
   205→            }
   206→        }
   207→        
   208→        // Human only restriction
   209→        if self.module_data.is_human_only_pickup {
   210→            if !self.is_human_player(other.get_controlling_player()) {
   211→                return false;
   212→            }
   213→        }
   214→        
   215→        // Science requirement
   216→        if self.module_data.pickup_science != ScienceType::Invalid {
   217→            if !self.player_has_science(other.get_controlling_player(), self.module_data.pickup_science) {
   218→                return false;
   219→            }
   220→        }
   221→        
   222→        // Cannot be picked up by parachutes
   223→        if self.is_kind_of(other, KINDOF_PARACHUTE) {
   224→            return false;
   225→        }
   226→        
   227→        true
   228→    }
