    50→/// This provides the core collision functionality that all collision
    51→/// modules must implement.
    52→pub trait CollideModuleInterface: Send + Sync {
    53→    /// Called when two objects collide (or when object collides with ground)
    54→    /// 
    55→    /// Note that 'other' can be None, indicating a collision with the ground.
    56→    /// This method handles the response for the object that THIS module belongs to.
    57→    fn on_collide(&mut self, other: Option<&dyn GameObject>, loc: &Coord3D, normal: &Coord3D) -> Result<(), CollisionError>;
    58→    
    59→    /// Check if this object would like to collide with another object
    60→    /// Used for things like pilots determining if they can "enter" something
    61→    fn would_like_to_collide_with(&self, other: &dyn GameObject) -> bool;
    62→    
    63→    /// Identification methods for specific collision types
    64→    fn is_hijacked_vehicle_crate_collide(&self) -> bool { false }
    65→    fn is_sabotage_building_crate_collide(&self) -> bool { false }
    66→    fn is_car_bomb_crate_collide(&self) -> bool { false }
    67→    fn is_railroad(&self) -> bool { false }
    68→    fn is_salvage_crate_collide(&self) -> bool { false }
    69→}
